// ===============================
// INPUT
// ===============================
const rawMarkdown = $input.item.json.pages?.markdown || '';
const documentId = $input.item.json.id || null;
const documentTitle = $input.item.json.name || null;
const slideNumber = ($input.item.json.pages?.index ?? 0) + 1;
const images = $input.item.json.pages?.images || [];
const imageCount = Array.isArray(images) ? images.length : 0;

// ===============================
// LINK EXTRACTION
// ===============================
const markdownLinkPattern = /\[([^\]]+)\]\(([^)]+)\)/g;
const extractedLinks = [];
let match;
while ((match = markdownLinkPattern.exec(rawMarkdown)) !== null) {
  extractedLinks.push({ text: match[1], url: match[2] });
}

const urlPattern = /(https?:\/\/[^\s]+)/g;
const plainUrls = rawMarkdown.match(urlPattern) || [];
const emailPattern = /\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Za-z]{2,}\b/g;
const emails = rawMarkdown.match(emailPattern) || [];

const allLinks = [
  ...extractedLinks,
  ...plainUrls.map(url => ({ text: 'URL', url })),
  ...emails.map(email => ({ text: 'Email', url: `mailto:${email}` }))
];

// ===============================
// CLEAN TEXT
// ===============================
let cleanedText = rawMarkdown
  .replace(/\\([^n])/g, '$1')
  .replace(/\\n/g, '\n')
  .replace(/(https?:\/\/[^\s]+)/g, '')
  .replace(/\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Za-z]{2,}\b/g, '')
  .replace(/!\[?[^\]]*\]?\([^)]*\)/g, '')
  .replace(/!?img[-_]?\d+\.(jpeg|jpg|png|gif|webp)/gi, '')
  .replace(/\$+/g, '')
  .replace(/\\[a-zA-Z]+\{([^}]*)\}/g, '$1')
  .replace(/[{}]/g, '')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&amp;/g, '&')
  .replace(/^#{1,6}\s+/gm, '')
  .replace(/(\*\*|__)(.*?)\1/g, '$2')
  .replace(/(\*|_)(.*?)\1/g, '$2')
  .replace(/\n{3,}/g, '\n\n')
  .replace(/[ \t]+/g, ' ')
  .replace(/^\s+|\s+$/gm, '')
  .trim();

cleanedText = cleanedText
  .split('\n')
  .filter(line => line.length > 0)
  .join('\n');

// ===============================
// FILTER LINKS
// ===============================
const uniqueLinks = Array.from(
  new Map(allLinks.map(link => [link.url, link])).values()
).filter(link => {
  if (!link.url || link.url.trim() === '') return false;
  if (/\.(jpeg|jpg|png|gif|webp|bmp|svg|tiff?)$/i.test(link.url)) return false;
  if (/^!?img[-_]?\d+$/i.test(link.url)) return false;
  return (
    link.url.startsWith('http://') ||
    link.url.startsWith('https://') ||
    link.url.startsWith('mailto:')
  );
});

// ===============================
// OUTPUT
// ===============================
return {
  json: {
    document_id: documentId,
    document_title: documentTitle,
    slide_number: slideNumber,
    content_type: "text",
    content: cleanedText,
    image_count: imageCount,
    links: uniqueLinks.length > 0 ? uniqueLinks : null
  }
};

// Extract content from Pixtral response
const content = $('Vision AI').item.json.choices[0].message.content;

// Clean markdown formatting from content
const cleanedContent = content
  .replace(/\*\*/g, '')           // Remove **bold**
  .replace(/\\n/g, ' ')            // Replace literal \n with space
  .replace(/\n+/g, ' ')            // Replace actual newlines with space
  .replace(/\s+/g, ' ')            // Collapse multiple spaces
  .trim();

// Return only cleaned text
return {
  json: {
    content: cleanedContent
  }
};

const items = $input.all();

// Ryhmittele document_id mukaan
const grouped = {};
items.forEach(item => {
  const docId = item.json.document_id;
  if (!grouped[docId]) {
    grouped[docId] = {
      document_id: docId,
      document_title: item.json.document_title,
      markdowns: []
    };
  }
  if (grouped[docId].markdowns.length < 3) {
    grouped[docId].markdowns.push(item.json.content || '');
  }
});

// Yhdistä markdownit ja palauta yksi item per esitelmä
return Object.values(grouped).map(doc => ({
  json: {
    document_id: doc.document_id,
    document_title: doc.document_title,
    combined_markdown: doc.markdowns.join('\n\n---\n\n')
  }
}));

