const items = $input.all();

return items.map(item => {
  const raw = item.json.output?.[0]?.content?.[0]?.text || '';
  const text = String(raw).replace(/\\n/g, '\n');

  const idMatch = text.match(/\*?\*?document_id\*?\*?[:\s]+(.+?)(?=\n|$)/i);
  const titleMatch = text.match(/\*?\*?document_title\*?\*?[:\s]+(.+?)(?=\n|$)/i);
  const topicMatch = text.match(/\*?\*?(?:Subject|Topic)\*?\*?[:\s]+(.+?)(?=\n\n|\n\*|$)/si);
  const summaryMatch = text.match(/\*?\*?Summary\*?\*?[:\s]+(.+?)$/si);

  return {
    json: {
      document_id: idMatch ? idMatch[1].trim() : null,
      document_title: titleMatch ? titleMatch[1].trim() : null,
      document_topic: topicMatch ? topicMatch[1].trim() : null,
      document_summary: summaryMatch ? summaryMatch[1].trim() : null
    }
  };
});
